1252 |     function smartJSONParse(jsonString) {
1253 |         try {
1254 |             return JSON.parse(jsonString);
1255 |         } catch (e) {
1256 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
1257 |             let fixed = jsonString
1258 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1259 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1260 |                 // 2. Fix literal newlines inside strings (replace with \n)
1261 |                 .replace(/(\n)/g, (match, p1, offset) => {
1262 |                     // Only replace if we are likely inside a quoted string
1263 |                     const before = jsonString.slice(0, offset);
1264 |                     const quoteCount = (before.match(/"/g) || []).length;
1265 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1266 |                 });
1267 | 
1268 |             try {
1269 |                 const cleanObj = JSON.parse(fixed);
1270 |                 document.getElementById('json-input').value = fixed;
1271 |                 if (typeof saveState === 'function') saveState();
1272 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
