1457 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1458 |     function applyLocalPatch(content, ops) {
1459 |         let lines = content.split('\n');
1460 |         let logs = [];
1461 |         let success = true;
1462 | 
1463 |         if (typeof ops === 'string') {
1464 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1465 |         }
1466 | 
1467 |         ops.forEach(op => {
1468 |             if (op.action === 'comment') return;
1469 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1470 |             
1471 |             if (op.action === 'replace_block') {
1472 |                 // Strategy 1: Exact String Match (Fastest)
1473 |                 const currentStr = lines.join('\n');
1474 |                 if (currentStr.includes(op.find_block)) {
1475 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1476 |                     logs.push('Exact match applied');
1477 |                     return;
1478 |                 }
1479 | 
1480 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1481 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1482 |                 if (searchLines.length === 0) return;
1483 | 
1484 |                 let matchStart = -1;
1485 |                 let matchEnd = -1;
1486 | 
1487 |                 // Scan file lines
1488 |                 for (let i = 0; i < lines.length; i++) {
1489 |                     // If first line matches (ignoring whitespace)
1490 |                     if (lines[i].trim() === searchLines[0]) {
1491 |                         // Check subsequent lines
1492 |                         let allMatch = true;
1493 |                         let fileOffset = 0;
1494 |                         let searchOffset = 1;
1495 |                         
1496 |                         while (searchOffset < searchLines.length) {
1497 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1498 |                             const nextFile = lines[i + fileOffset + 1].trim();
1499 |                             // Skip empty lines in file if they aren't in search block
1500 |                             if (nextFile === '') {
1501 |                                 fileOffset++;
1502 |                                 continue;
1503 |                             }
1504 |                             if (nextFile !== searchLines[searchOffset]) {
1505 |                                 allMatch = false;
1506 |                                 break;
1507 |                             }
1508 |                             fileOffset++;
1509 |                             searchOffset++;
1510 |                         }
1511 | 
1512 |                         if (allMatch) {
1513 |                             matchStart = i;
1514 |                             matchEnd = i + fileOffset;
1515 |                             break;
1516 |                         }
1517 |                     }
1518 |                 }
1519 | 
1520 |                 if (matchStart !== -1) {
1521 |                     // Replace the range of lines
