1558 |                         error: err 
1559 |                     })
1560 |                 });
1561 |                 const data = await res.json();
1562 |                 const ops = data.operations;
1563 | 
1564 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
1565 | 
