3862 |     function formatBytes(bytes) {
3863 |         if (!bytes) return '0 B';
3864 |         const k = 1024;
3865 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3866 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3867 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3868 |     }
