3870 |     function timeAgo(dateString) {
3871 |         const date = new Date(dateString);
3872 |         const now = new Date();
3873 |         const seconds = Math.floor((now - date) / 1000);
3874 |         if (seconds < 10) return 'just now';
3875 |         if (seconds < 60) return seconds + 's ago';
3876 |         const minutes = Math.floor(seconds / 60);
3877 |         if (minutes < 60) return minutes + 'm ago';
3878 |         const hours = Math.floor(minutes / 60);
3879 |         if (hours < 24) return hours + 'h ago';
3880 |         return date.toLocaleDateString();
3881 |     }
