 563 |     async function openSyntaxReport(path, error) {
 564 |         const modal = document.getElementById('syntax-report-modal');
 565 |         const pathEl = document.getElementById('sr-path');
 566 |         const msgEl = document.getElementById('sr-message');
 567 |         const codeEl = document.getElementById('sr-code');
 568 |         const fixBtn = document.getElementById('btn-auto-fix-wasm');
 569 |         
 570 |         pathEl.innerText = path;
 571 |         msgEl.innerHTML = `<strong>Line ${error.line}, Col ${error.column || '?'}:</strong> ${error.message}`;
 572 |         codeEl.innerText = "Loading context...";
 573 |         modal.style.display = 'flex';
 574 |         fixBtn.style.display = 'none'; // Hide until we verify deterministic fix
 575 | 
 576 |         // Fetch File Content
 577 |         try {
 578 |             const res = await fetch(CONFIG.funcUrl, { 
 579 |                 method: 'POST', headers: {'Content-Type': 'application/json'}, 
 580 |                 body: apiBody({ action: 'preview_file', file_path: path }) 
 581 |             });
 582 |             const data = await res.json();
 583 |             const fullCode = b64DecodeUnicode(data.content || "");
 584 |             
 585 |             // Window: 5 lines before and after
 586 |             const lines = fullCode.split('\n');
 587 |             const start = Math.max(0, error.line - 6);
 588 |             const end = Math.min(lines.length, error.line + 5);
 589 |             
 590 |             let snippet = "";
 591 |             for (let i = start; i < end; i++) {
 592 |                 const lineNum = i + 1;
 593 |                 const marker = (lineNum === error.line) ? "> " : "  ";
 594 |                 snippet += `${marker}${lineNum.toString().padEnd(4)} | ${lines[i]}\n`;
 595 |             }
 596 |             
 597 |             codeEl.innerText = snippet;
 598 |             
 599 |             // Store for fix application
 600 |             currentSyntaxContext = { file: path, error: error, code: fullCode, ops: null };
 601 | 
 602 |             // Check for Deterministic Fix Availability
 603 |             checkDeterministicFix(path, error, fullCode);
 604 | 
 605 |         } catch(e) {
 606 |             codeEl.innerText = "Failed to load file content: " + e.message;
 607 |         }
 608 |     }
