1380 |     function formatBytes(bytes) {
1381 |         if (!bytes) return '0 B';
1382 |         const k = 1024;
1383 |         const sizes = ['B', 'KB', 'MB', 'GB'];
1384 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
1385 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
1386 |     }
