1388 |     function timeAgo(dateString) {
1389 |         const date = new Date(dateString);
1390 |         const now = new Date();
1391 |         const seconds = Math.floor((now - date) / 1000);
1392 |         if (seconds < 10) return 'just now';
1393 |         if (seconds < 60) return seconds + 's ago';
1394 |         const minutes = Math.floor(seconds / 60);
1395 |         if (minutes < 60) return minutes + 'm ago';
1396 |         const hours = Math.floor(minutes / 60);
1397 |         if (hours < 24) return hours + 'h ago';
1398 |         return date.toLocaleDateString();
1399 |     }
