1516 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
1517 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
1518 |         
1519 |         const navItems = document.querySelectorAll('.nav-item');
1520 |         switchTab(tabId, navItems[navIndex]);
1521 | 
1522 |         const scrollContainer = document.querySelector('.main-view');
1523 |         let retryCount = 0;
1524 |         const MAX_RETRIES = 5;
1525 | 
1526 |         const attemptNavigation = async () => {
1527 |             const element = document.querySelector(selector);
1528 |             
1529 |             if (element) {
1530 |                 console.log("[DeepJump] Element found. Scrolling...");
1531 |                 
1532 |                 // Wait for any tab transition animations
1533 |                 await new Promise(r => setTimeout(r, 300));
1534 | 
1535 |                 let offsetTop = 0;
1536 |                 let curr = element;
1537 |                 while (curr && curr !== scrollContainer) {
1538 |                     offsetTop += curr.offsetTop;
1539 |                     curr = curr.offsetParent;
1540 |                 }
1541 | 
1542 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
1543 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
1544 | 
1545 |                 // Visual Highlight
1546 |                 element.style.transition = 'all 0.5s ease';
1547 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
1548 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
1549 |                 setTimeout(() => {
1550 |                     element.style.backgroundColor = '';
1551 |                     element.style.boxShadow = '';
1552 |                 }, 3000);
1553 |                 
1554 |                 console.groupEnd();
1555 |                 return true;
1556 |             }
1557 | 
1558 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
1559 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
1560 |                 retryCount++;
1561 |                 showGlobalToast("🔍 Searching deeper...");
1562 |                 
1563 |                 await loadMoreFn(); 
1564 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
1565 |                 return attemptNavigation();
1566 |             }
1567 | 
1568 |             console.error("[DeepJump] Failed: Element not found after retries.");
1569 |             showGlobalToast("Entry not found in recent history.", true);
1570 |             console.groupEnd();
1571 |             return false;
1572 |         };
1573 | 
1574 |         setTimeout(attemptNavigation, 100);
1575 |     }
