const baseScript = doc.createElement('script');
baseScript.textContent = `
    window.IS_CONDUIT_PREVIEW = true;
    window.process = { env: { NODE_ENV: "development" } };

    // --- CIRCULAR SAFE SERIALIZER ---
    const safeStringify = (obj) => {
        const cache = new Set();
        return JSON.stringify(obj, (key, value) => {
            if (typeof value === 'object' && value !== null) {
                if (cache.has(value)) return '[Circular]';
                cache.add(value);
            }
            if (value instanceof HTMLElement) return value.outerHTML.substring(0, 100) + '...';
            return value;
        }, 2);
    };

    // --- CONSOLE INTERCEPTOR ---
    ['log', 'warn', 'error', 'debug', 'info'].forEach(method => {
        const original = console[method];
        console[method] = (...args) => {
            window.parent.postMessage({ 
                type: 'CONDUIT_LOG', 
                method, 
                args: args.map(a => typeof a === 'object' ? JSON.parse(safeStringify(a)) : a),
                time: new Date().toLocaleTimeString([], {hour12:false, hour:'2-digit', minute:'2-digit', second:'2-digit'})
            }, '*');
            original.apply(console, args);
        };
    });

    // --- NETWORK INTERCEPTOR (FETCH) ---
    const originalFetch = window.fetch;
    window.fetch = async (...args) => {
        const start = Date.now();
        const url = args[0];
        const options = args[1] || {};
        try {
            const response = await originalFetch(...args);
            const clone = response.clone();
            const duration = Date.now() - start;
            let resBody = '[Binary Data]';
            try { resBody = await clone.json(); } catch(e) { try { resBody = await clone.text(); } catch(e2){} }

            window.parent.postMessage({
                type: 'CONDUIT_NETWORK',
                payload: {
                    url, method: options.method || 'GET',
                    status: response.status, duration,
                    requestBody: options.body || null,
                    responseBody: resBody
                }
            }, '*');
            return response;
        } catch(err) {
            window.parent.postMessage({ type: 'CONDUIT_LOG', method: 'error', args: ['Fetch Failed: ' + url, err.message], time: '' }, '*');
            throw err;
        }
    };
`;
doc.head.prepend(baseScript);

ops.find_block:
async function deleteWorkflowRun(runId) {
    if (!confirm("⚠️ Are you sure you want to delete this workflow run from GitHub?\nThis action cannot be undone.")) return;

    const toast = document.createElement('div');
    toast.innerText = "Deleting Run...";
    toast.style.cssText = "position:fixed; bottom:100px; left:50%; transform:translateX(-50%); background:var(--danger); color:white; padding:10px 20px; border-radius:30px; z-index:9999;";
    document.body.appendChild(toast);

    try {
        const res = await fetch(CONFIG.funcUrl, {
            method: 'POST', headers: {'Content-Type': 'application/json'},
            body: apiBody({ action: 'delete_run', run_id: runId })
        });
        const data = await res.json();
        toast.remove();

        if (data.success) {
            showGlobalToast("Workflow run deleted");
            const el = document.querySelector(`div[data-run-id="${runId}"]`);
            if (el) {
                el.style.transition = "all 0.3s";
                el.style.height = "0";
                el.style.opacity = "0";
                el.style.padding = "0";
                setTimeout(() => el.remove(), 300);
            }
            setTimeout(() => { loadWorkflows(); fetchState(false, false); }, 1000);
        } else {
            showGlobalToast("Failed to delete run", true);
        }
    } catch (e) {
        toast.remove();
        showGlobalToast("Error: " + e.message, true);
    }
}

