1485 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1486 |     function applyLocalPatch(content, ops) {
1487 |         let lines = content.split('\n');
1488 |         let logs = [];
1489 |         let success = true;
1490 | 
1491 |         if (typeof ops === 'string') {
1492 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1493 |         }
1494 | 
1495 |         ops.forEach(op => {
1496 |             if (op.action === 'comment') return;
1497 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1498 |             
1499 |             if (op.action === 'replace_block') {
1500 |                 // Strategy 1: Exact String Match (Fastest)
1501 |                 const currentStr = lines.join('\n');
1502 |                 if (currentStr.includes(op.find_block)) {
1503 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1504 |                     logs.push('Exact match applied');
1505 |                     return;
1506 |                 }
1507 | 
1508 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1509 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1510 |                 if (searchLines.length === 0) return;
1511 | 
1512 |                 let matchStart = -1;
1513 |                 let matchEnd = -1;
1514 | 
1515 |                 // Scan file lines
1516 |                 for (let i = 0; i < lines.length; i++) {
1517 |                     // If first line matches (ignoring whitespace)
1518 |                     if (lines[i].trim() === searchLines[0]) {
1519 |                         // Check subsequent lines
1520 |                         let allMatch = true;
1521 |                         let fileOffset = 0;
1522 |                         let searchOffset = 1;
1523 |                         
1524 |                         while (searchOffset < searchLines.length) {
1525 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1526 |                             const nextFile = lines[i + fileOffset + 1].trim();
1527 |                             // Skip empty lines in file if they aren't in search block
1528 |                             if (nextFile === '') {
1529 |                                 fileOffset++;
1530 |                                 continue;
1531 |                             }
1532 |                             if (nextFile !== searchLines[searchOffset]) {
1533 |                                 allMatch = false;
1534 |                                 break;
1535 |                             }
1536 |                             fileOffset++;
1537 |                             searchOffset++;
1538 |                         }
1539 | 
1540 |                         if (allMatch) {
1541 |                             matchStart = i;
1542 |                             matchEnd = i + fileOffset;
1543 |                             break;
1544 |                         }
1545 |                     }
1546 |                 }
1547 | 
1548 |                 if (matchStart !== -1) {
1549 |                     // Replace the range of lines
1550 |                     const replacement = op.replace_with.split('\n');
1551 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1552 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1553 |                 } else {
1554 |                     success = false;
1555 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1556 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1557 |                 }
1558 |             }
1559 |         });
1560 |         return { content: lines.join('\n'), success, logs };
1561 |     }
