3949 |     function formatBytes(bytes) {
3950 |         if (!bytes) return '0 B';
3951 |         const k = 1024;
3952 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3953 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3954 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3955 |     }
