3957 |     function timeAgo(dateString) {
3958 |         const date = new Date(dateString);
3959 |         const now = new Date();
3960 |         const seconds = Math.floor((now - date) / 1000);
3961 |         if (seconds < 10) return 'just now';
3962 |         if (seconds < 60) return seconds + 's ago';
3963 |         const minutes = Math.floor(seconds / 60);
3964 |         if (minutes < 60) return minutes + 'm ago';
3965 |         const hours = Math.floor(minutes / 60);
3966 |         if (hours < 24) return hours + 'h ago';
3967 |         return date.toLocaleDateString();
3968 |     }
