4085 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
4086 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
4087 |         
4088 |         const navItems = document.querySelectorAll('.nav-item');
4089 |         switchTab(tabId, navItems[navIndex]);
4090 | 
4091 |         const scrollContainer = document.querySelector('.main-view');
4092 |         let retryCount = 0;
4093 |         const MAX_RETRIES = 5;
4094 | 
4095 |         const attemptNavigation = async () => {
4096 |             const element = document.querySelector(selector);
4097 |             
4098 |             if (element) {
4099 |                 console.log("[DeepJump] Element found. Scrolling...");
4100 |                 
4101 |                 // Wait for any tab transition animations
4102 |                 await new Promise(r => setTimeout(r, 300));
4103 | 
4104 |                 let offsetTop = 0;
4105 |                 let curr = element;
4106 |                 while (curr && curr !== scrollContainer) {
4107 |                     offsetTop += curr.offsetTop;
4108 |                     curr = curr.offsetParent;
4109 |                 }
4110 | 
4111 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
4112 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
4113 | 
4114 |                 // Visual Highlight
4115 |                 element.style.transition = 'all 0.5s ease';
4116 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
4117 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
4118 |                 setTimeout(() => {
4119 |                     element.style.backgroundColor = '';
4120 |                     element.style.boxShadow = '';
4121 |                 }, 3000);
4122 |                 
4123 |                 console.groupEnd();
4124 |                 return true;
4125 |             }
4126 | 
4127 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
4128 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
4129 |                 retryCount++;
4130 |                 showGlobalToast("🔍 Searching deeper...");
4131 |                 
4132 |                 await loadMoreFn(); 
4133 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
4134 |                 return attemptNavigation();
4135 |             }
4136 | 
4137 |             console.error("[DeepJump] Failed: Element not found after retries.");
4138 |             showGlobalToast("Entry not found in recent history.", true);
4139 |             console.groupEnd();
4140 |             return false;
4141 |         };
4142 | 
4143 |         setTimeout(attemptNavigation, 100);
4144 |     }
