5083 |         const data = window.OP_CACHE[id];
5084 |         if(!data) return;
5085 |         
5086 |         const viewer = document.getElementById('diff-viewer');
5087 |         const title = document.getElementById('diff-title');
5088 |         
5089 |         viewer.classList.add('active');
5090 |         toggleFab(false);
5091 |         title.innerText = `Comparing: ${data.file.split('/').pop()}`;
5092 |         
5093 |         if(!diffLeft) {
5094 |             diffLeft = ace.edit("diff-left");
5095 |             diffLeft.setTheme("ace/theme/tomorrow_night_bright");
5096 |             diffLeft.setReadOnly(true);
5097 |             diffLeft.setOption("showPrintMargin", false);
5098 |             
5099 |             diffRight = ace.edit("diff-right");
5100 |             diffRight.setTheme("ace/theme/tomorrow_night_bright");
5101 |             diffRight.setReadOnly(true);
5102 |             diffRight.setOption("showPrintMargin", false);
5103 | 
5104 |             diffLeft.session.on('changeScrollTop', (top) => diffRight.session.setScrollTop(top));
5105 |             diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
5106 |             diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
5107 |             diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
5108 |         }
5109 | 
5110 |         diffLeft.setValue("Loading...", -1);
5111 |         diffRight.setValue("Loading...", -1);
5112 | 
5113 |         try {
5114 |             let leftContent = "", rightContent = "";
5115 | 
5116 |             if (forcedLeft !== null && forcedRight !== null) {
5117 |                 leftContent = forcedLeft;
5118 |                 rightContent = forcedRight;
5119 |             } else {
5120 |                 const rightRef = data.commit_sha || 'HEAD';
5121 |                 const leftRef = rightRef + '^';
5122 | 
5123 |                 const fetchFile = async (ref) => {
5124 |                     const res = await fetch(CONFIG.funcUrl, {
5125 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
5126 |                         body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
5127 |                     });
5128 |                     const d = await res.json();
5129 |                     return d.content ? b64DecodeUnicode(d.content) : '';
5130 |                 };
5131 | 
5132 |                 const results = await Promise.all([
5133 |                     fetchFile(leftRef).catch(() => ""),
5134 |                     fetchFile(rightRef).catch(() => "")
5135 |                 ]);
5136 |                 leftContent = results[0];
5137 |                 rightContent = results[1];
5138 |             }
5139 | 
5140 |             let mode = "ace/mode/text";
5141 |             if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
5142 |             else if (data.file.endsWith('.html')) mode = "ace/mode/html";
5143 |             else if (data.file.endsWith('.css')) mode = "ace/mode/css";
5144 |             else if (data.file.endsWith('.json')) mode = "ace/mode/json";
5145 |             else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";
5146 |             
5147 |             diffLeft.session.setMode(mode);
5148 |             diffLeft.setValue(leftContent, -1);
5149 |             
5150 |             diffRight.session.setMode(mode);
5151 |             diffRight.setValue(rightContent, -1);
5152 | 
5153 |             const Range = ace.require('ace/range').Range;
5154 | 
5155 |             // Helper to get Range from String Index
5156 |             const getRangeFromText = (session, searchText) => {
5157 |                 const fullText = session.getValue();
5158 |                 // 1. Try Exact Match
5159 |                 let startIdx = fullText.indexOf(searchText);
5160 |                 
5161 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
5162 |                 if (startIdx === -1) {
5163 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
5164 |                     startIdx = clean(fullText).indexOf(clean(searchText));
5165 |                 }
5166 | 
5167 |                 if (startIdx !== -1) {
5168 |                     const linesBefore = fullText.substring(0, startIdx).split('\n');
5169 |                     const startRow = linesBefore.length - 1;
5170 |                     const startCol = linesBefore[startRow].length;
5171 |                     const linesInSearch = searchText.split('\n');
5172 |                     const endRow = startRow + linesInSearch.length - 1;
5173 |                     const endCol = linesInSearch.length > 1 ? linesInSearch[linesInSearch.length - 1].length : startCol + searchText.length;
5174 |                     return new Range(startRow, startCol, endRow, endCol);
5175 |                 }
5176 |                 return null;
5177 |             };
5178 |             
5179 |             const searchRemove = data.op.find_block || data.op.anchor;
5180 |             if(searchRemove) {
5181 |                 const range = getRangeFromText(diffLeft.session, String(searchRemove));
5182 |                 if(range) {
5183 |                     diffLeft.session.addMarker(range, "marker-remove", "fullLine");
5184 |                     diffLeft.scrollToLine(range.start.row, true, true, function() {});
5185 |                 }
5186 |             }
5187 | 
5188 |             const searchAdd = data.op.replace_with || data.op.content;
5189 |             if(searchAdd) {
5190 |                 const range = getRangeFromText(diffRight.session, String(searchAdd));
5191 |                 if(range) {
5192 |                     diffRight.session.addMarker(range, "marker-add", "fullLine");
5193 |                     diffRight.scrollToLine(range.start.row, true, true, function() {});
5194 |                 }
5195 |             }
5196 | 
5197 |         } catch(e) {
5198 |             diffLeft.setValue("Error: " + e.message, -1);
5199 |         }
5200 |     }
