1306 |             let fixed = jsonString
1307 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1308 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1309 |                 // 2. Fix literal newlines inside strings (replace with \n)
