1311 |                     // Only replace if we are likely inside a quoted string
1312 |                     const before = jsonString.slice(0, offset);
1313 |                     const quoteCount = (before.match(/"/g) || []).length;
1314 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1315 |                 });
1316 | 
1317 |             try {
1318 |                 const cleanObj = JSON.parse(fixed);
