1506 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1507 |     function applyLocalPatch(content, ops) {
1508 |         let lines = content.split('\n');
1509 |         let logs = [];
1510 |         let success = true;
1511 | 
1512 |         if (typeof ops === 'string') {
1513 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1514 |         }
1515 | 
1516 |         ops.forEach(op => {
1517 |             if (op.action === 'comment') return;
1518 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1519 |             
1520 |             if (op.action === 'replace_block') {
1521 |                 // Strategy 1: Exact String Match (Fastest)
1522 |                 const currentStr = lines.join('\n');
1523 |                 if (currentStr.includes(op.find_block)) {
1524 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1525 |                     logs.push('Exact match applied');
1526 |                     return;
1527 |                 }
1528 | 
1529 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1530 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1531 |                 if (searchLines.length === 0) return;
1532 | 
1533 |                 let matchStart = -1;
1534 |                 let matchEnd = -1;
1535 | 
1536 |                 // Scan file lines
1537 |                 for (let i = 0; i < lines.length; i++) {
1538 |                     // If first line matches (ignoring whitespace)
1539 |                     if (lines[i].trim() === searchLines[0]) {
1540 |                         // Check subsequent lines
1541 |                         let allMatch = true;
1542 |                         let fileOffset = 0;
1543 |                         let searchOffset = 1;
1544 |                         
1545 |                         while (searchOffset < searchLines.length) {
1546 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1547 |                             const nextFile = lines[i + fileOffset + 1].trim();
1548 |                             // Skip empty lines in file if they aren't in search block
1549 |                             if (nextFile === '') {
1550 |                                 fileOffset++;
1551 |                                 continue;
1552 |                             }
1553 |                             if (nextFile !== searchLines[searchOffset]) {
1554 |                                 allMatch = false;
1555 |                                 break;
1556 |                             }
1557 |                             fileOffset++;
1558 |                             searchOffset++;
1559 |                         }
1560 | 
1561 |                         if (allMatch) {
1562 |                             matchStart = i;
1563 |                             matchEnd = i + fileOffset;
1564 |                             break;
1565 |                         }
1566 |                     }
1567 |                 }
1568 | 
1569 |                 if (matchStart !== -1) {
1570 |                     // Replace the range of lines
1571 |                     const replacement = op.replace_with.split('\n');
1572 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1573 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1574 |                 } else {
1575 |                     success = false;
1576 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1577 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1578 |                 }
1579 |             }
1580 |         });
1581 |         return { content: lines.join('\n'), success, logs };
1582 |     }
