3970 |     function formatBytes(bytes) {
3971 |         if (!bytes) return '0 B';
3972 |         const k = 1024;
3973 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3974 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3975 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3976 |     }
