3978 |     function timeAgo(dateString) {
3979 |         const date = new Date(dateString);
3980 |         const now = new Date();
3981 |         const seconds = Math.floor((now - date) / 1000);
3982 |         if (seconds < 10) return 'just now';
3983 |         if (seconds < 60) return seconds + 's ago';
3984 |         const minutes = Math.floor(seconds / 60);
3985 |         if (minutes < 60) return minutes + 'm ago';
3986 |         const hours = Math.floor(minutes / 60);
3987 |         if (hours < 24) return hours + 'h ago';
3988 |         return date.toLocaleDateString();
3989 |     }
