4106 |     async function jumpToElement(selector, tabId, navIndex, loadMoreFn) {
4107 |         console.group(`[DeepJump] Target: ${selector} in ${tabId}`);
4108 |         
4109 |         const navItems = document.querySelectorAll('.nav-item');
4110 |         switchTab(tabId, navItems[navIndex]);
4111 | 
4112 |         const scrollContainer = document.querySelector('.main-view');
4113 |         let retryCount = 0;
4114 |         const MAX_RETRIES = 5;
4115 | 
4116 |         const attemptNavigation = async () => {
4117 |             const element = document.querySelector(selector);
4118 |             
4119 |             if (element) {
4120 |                 console.log("[DeepJump] Element found. Scrolling...");
4121 |                 
4122 |                 // Wait for any tab transition animations
4123 |                 await new Promise(r => setTimeout(r, 300));
4124 | 
4125 |                 let offsetTop = 0;
4126 |                 let curr = element;
4127 |                 while (curr && curr !== scrollContainer) {
4128 |                     offsetTop += curr.offsetTop;
4129 |                     curr = curr.offsetParent;
4130 |                 }
4131 | 
4132 |                 const targetScroll = offsetTop - (scrollContainer.clientHeight / 2) + (element.clientHeight / 2);
4133 |                 scrollContainer.scrollTo({ top: targetScroll, behavior: 'smooth' });
4134 | 
4135 |                 // Visual Highlight
4136 |                 element.style.transition = 'all 0.5s ease';
4137 |                 element.style.backgroundColor = 'rgba(59, 130, 246, 0.3)';
4138 |                 element.style.boxShadow = '0 0 30px rgba(59, 130, 246, 0.6)';
4139 |                 setTimeout(() => {
4140 |                     element.style.backgroundColor = '';
4141 |                     element.style.boxShadow = '';
4142 |                 }, 3000);
4143 |                 
4144 |                 console.groupEnd();
4145 |                 return true;
4146 |             }
4147 | 
4148 |             if (retryCount < MAX_RETRIES && loadMoreFn) {
4149 |                 console.log(`[DeepJump] Not found. Triggering loadMore (Attempt ${retryCount + 1})...`);
4150 |                 retryCount++;
4151 |                 showGlobalToast("🔍 Searching deeper...");
4152 |                 
4153 |                 await loadMoreFn(); 
4154 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
4155 |                 return attemptNavigation();
4156 |             }
4157 | 
4158 |             console.error("[DeepJump] Failed: Element not found after retries.");
4159 |             showGlobalToast("Entry not found in recent history.", true);
4160 |             console.groupEnd();
4161 |             return false;
4162 |         };
4163 | 
4164 |         setTimeout(attemptNavigation, 100);
4165 |     }
