5125 |             diffLeft.session.on('changeScrollTop', (top) => diffRight.session.setScrollTop(top));
5126 |             diffRight.session.on('changeScrollTop', (top) => diffLeft.session.setScrollTop(top));
5127 |             diffLeft.session.on('changeScrollLeft', (left) => diffRight.session.setScrollLeft(left));
5128 |             diffRight.session.on('changeScrollLeft', (left) => diffLeft.session.setScrollLeft(left));
5129 |         }
5130 | 
5131 |         diffLeft.setValue("Loading...", -1);
5132 |         diffRight.setValue("Loading...", -1);
5133 | 
5134 |         try {
5135 |             let leftContent = "", rightContent = "";
5136 | 
5137 |             if (forcedLeft !== null && forcedRight !== null) {
5138 |                 leftContent = forcedLeft;
5139 |                 rightContent = forcedRight;
5140 |             } else {
5141 |                 const rightRef = data.commit_sha || 'HEAD';
5142 |                 const leftRef = rightRef + '^';
5143 | 
5144 |                 const fetchFile = async (ref) => {
5145 |                     const res = await fetch(CONFIG.funcUrl, {
5146 |                         method: 'POST', headers: {'Content-Type': 'application/json'},
5147 |                         body: apiBody({ action: 'preview_file', file_path: data.file, ref_sha: ref })
5148 |                     });
5149 |                     const d = await res.json();
5150 |                     return d.content ? b64DecodeUnicode(d.content) : '';
5151 |                 };
5152 | 
5153 |                 const results = await Promise.all([
5154 |                     fetchFile(leftRef).catch(() => ""),
5155 |                     fetchFile(rightRef).catch(() => "")
5156 |                 ]);
5157 |                 leftContent = results[0];
5158 |                 rightContent = results[1];
5159 |             }
5160 | 
5161 |             let mode = "ace/mode/text";
5162 |             if (data.file.endsWith('.js')) mode = "ace/mode/javascript";
5163 |             else if (data.file.endsWith('.html')) mode = "ace/mode/html";
5164 |             else if (data.file.endsWith('.css')) mode = "ace/mode/css";
5165 |             else if (data.file.endsWith('.json')) mode = "ace/mode/json";
5166 |             else if (data.file.endsWith('.md')) mode = "ace/mode/markdown";
5167 |             
5168 |             diffLeft.session.setMode(mode);
5169 |             diffLeft.setValue(leftContent, -1);
5170 |             
5171 |             diffRight.session.setMode(mode);
5172 |             diffRight.setValue(rightContent, -1);
5173 | 
5174 |             const Range = ace.require('ace/range').Range;
5175 | 
5176 |             // Helper to get Range from String Index
5177 |             const getRangeFromText = (session, searchText) => {
5178 |                 const fullText = session.getValue();
5179 |                 // 1. Try Exact Match
5180 |                 let startIdx = fullText.indexOf(searchText);
5181 |                 
5182 |                 // 2. Try Robust Match (Ignoring Line Endings differences)
5183 |                 if (startIdx === -1) {
5184 |                     const clean = (s) => s.replace(/\r\n/g, '\n').trim();
5185 |                     startIdx = clean(fullText).indexOf(clean(searchText));
5186 |                 }
5187 | 
5188 |                 if (startIdx !== -1) {
5189 |                     const linesBefore = fullText.substring(0, startIdx).split('\n');
5190 |                     const startRow = linesBefore.length - 1;
5191 |                     const startCol = linesBefore[startRow].length;
5192 |                     const linesInSearch = searchText.split('\n');
5193 |                     const endRow = startRow + linesInSearch.length - 1;
5194 |                     const endCol = linesInSearch.length > 1 ? linesInSearch[linesInSearch.length - 1].length : startCol + searchText.length;
5195 |                     return new Range(startRow, startCol, endRow, endCol);
5196 |                 }
5197 |                 return null;
5198 |             };
5199 |             
5200 |             const searchRemove = data.op.find_block || data.op.anchor;
5201 |             if(searchRemove) {
5202 |                 const range = getRangeFromText(diffLeft.session, String(searchRemove));
5203 |                 if(range) {
