1320 |     /**
1321 |      * Tries to parse JSON. If it fails due to bad escaping (common with AI),
1322 |      * it attempts to double-escape backslashes that aren't valid JSON control chars.
1323 |      */
1324 |     function smartJSONParse(jsonString) {
1325 |         try {
1326 |             return JSON.parse(jsonString);
1327 |         } catch (e) {
1328 |             console.warn("Standard JSON parse failed, attempting Robust Auto-Fix...");
1329 |             let fixed = jsonString
1330 |                 // 1. Fix backslashes that aren't part of a valid escape sequence
1331 |                 .replace(/\\(?!["\\/bfnrtu])/g, "\\\\")
1332 |                 // 2. Fix literal newlines inside strings (replace with \n)
1333 |                 .replace(/(\n)/g, (match, p1, offset) => {
1334 |                     // Only replace if we are likely inside a quoted string
1335 |                     const before = jsonString.slice(0, offset);
1336 |                     const quoteCount = (before.match(/"/g) || []).length;
1337 |                     return (quoteCount % 2 === 1) ? "\\n" : "\n";
1338 |                 });
1339 | 
1340 |             try {
1341 |                 const cleanObj = JSON.parse(fixed);
1342 |                 document.getElementById('json-input').value = fixed;
1343 |                 if (typeof saveState === 'function') saveState();
1344 |                 showGlobalToast("✨ Robust Auto-Correction Applied");
1345 |                 return cleanObj;
1346 |             } catch (e2) {
1347 |                 console.error("Robust fix failed:", e2);
1348 |                 throw e; // Throw original error for better debugging
1349 |             }
1350 |         }
1351 |     }
