1370 |     function resolvePath(base, relative) {
1371 |         const stack = base.split('/');
1372 |         stack.pop(); 
1373 |         const parts = relative.split('/');
1374 |         for (let i = 0; i < parts.length; i++) {
1375 |             if (parts[i] === '.') continue;
1376 |             if (parts[i] === '..') stack.pop();
1377 |             else stack.push(parts[i]);
1378 |         }
1379 |         return stack.join('/');
1380 |     }
