1529 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
1530 |     function applyLocalPatch(content, ops) {
1531 |         let lines = content.split('\n');
1532 |         let logs = [];
1533 |         let success = true;
1534 | 
1535 |         if (typeof ops === 'string') {
1536 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
1537 |         }
1538 | 
1539 |         ops.forEach(op => {
1540 |             if (op.action === 'comment') return;
1541 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
1542 |             
1543 |             if (op.action === 'replace_block') {
1544 |                 // Strategy 1: Exact String Match (Fastest)
1545 |                 const currentStr = lines.join('\n');
1546 |                 if (currentStr.includes(op.find_block)) {
1547 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
1548 |                     logs.push('Exact match applied');
1549 |                     return;
1550 |                 }
1551 | 
1552 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
1553 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
1554 |                 if (searchLines.length === 0) return;
1555 | 
1556 |                 let matchStart = -1;
1557 |                 let matchEnd = -1;
1558 | 
1559 |                 // Scan file lines
1560 |                 for (let i = 0; i < lines.length; i++) {
1561 |                     // If first line matches (ignoring whitespace)
1562 |                     if (lines[i].trim() === searchLines[0]) {
1563 |                         // Check subsequent lines
1564 |                         let allMatch = true;
1565 |                         let fileOffset = 0;
1566 |                         let searchOffset = 1;
1567 |                         
1568 |                         while (searchOffset < searchLines.length) {
1569 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
1570 |                             const nextFile = lines[i + fileOffset + 1].trim();
1571 |                             // Skip empty lines in file if they aren't in search block
1572 |                             if (nextFile === '') {
1573 |                                 fileOffset++;
1574 |                                 continue;
1575 |                             }
1576 |                             if (nextFile !== searchLines[searchOffset]) {
1577 |                                 allMatch = false;
1578 |                                 break;
1579 |                             }
1580 |                             fileOffset++;
1581 |                             searchOffset++;
1582 |                         }
1583 | 
1584 |                         if (allMatch) {
1585 |                             matchStart = i;
1586 |                             matchEnd = i + fileOffset;
1587 |                             break;
1588 |                         }
1589 |                     }
1590 |                 }
1591 | 
1592 |                 if (matchStart !== -1) {
1593 |                     // Replace the range of lines
1594 |                     const replacement = op.replace_with.split('\n');
1595 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
1596 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
1597 |                 } else {
1598 |                     success = false;
1599 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
1600 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
1601 |                 }
1602 |             }
1603 |         });
1604 |         return { content: lines.join('\n'), success, logs };
1605 |     }
