1609 |     async function runAutoFixLoop(name, code, errorList) {
1610 |         const status = document.getElementById('ef-status-msg');
1611 |         let currentCode = code;
1612 |         let currentErrors = errorList;
1613 | 
1614 |         // Fix one by one (recursive loop)
1615 |         async function fixNext(index) {
1616 |             if (index >= currentErrors.length) return true; // All initial errors processed
1617 | 
1618 |             const err = currentErrors[index];
1619 |             status.innerText = `🔧 Fixing Error ${index + 1}/${currentErrors.length} (Line ${err.line})...`;
1620 |             status.style.color = "#eab308"; // Dev yellow
1621 | 
1622 |             try {
1623 |                 // 1. Get Patch from AI
1624 |                 const res = await fetch(CONFIG.funcUrl, { 
1625 |                     method: 'POST', 
1626 |                     headers: {'Content-Type': 'application/json'},
1627 |                     body: apiBody({ 
1628 |                         action: 'propose_syntax_fix', 
1629 |                         code: currentCode, 
1630 |                         error: err 
1631 |                     })
1632 |                 });
1633 |                 const data = await res.json();
1634 |                 const ops = data.operations;
1635 | 
1636 |                 if (!ops || ops === "[]") throw new Error("AI could not generate a fix.");
1637 | 
1638 |                 // 2. Apply Patch Locally
1639 |                 const patchResult = applyLocalPatch(currentCode, ops);
1640 |                 if (!patchResult.success) throw new Error("Generated patch did not match code.");
1641 | 
1642 |                 currentCode = patchResult.content;
1643 |                 document.getElementById('ef-code').value = currentCode; // Update UI
1644 | 
1645 |                 // 3. Re-Validate
1646 |                 const scanRes = await fetch(CONFIG.funcUrl, { 
1647 |                     method: 'POST', headers: {'Content-Type': 'application/json'},
1648 |                     body: apiBody({ action: 'validate_syntax_deep', code_block: currentCode, file_path: 'index.ts' })
1649 |                 });
1650 |                 const scanData = await scanRes.json();
1651 | 
1652 |                 if (scanData.valid) {
1653 |                     status.innerText = "✅ Syntax Fixed!";
1654 |                     return true;
1655 |                 } else {
1656 |                     // If errors remain, update list and Prompt user
1657 |                     currentErrors = scanData.errors;
1658 |                     if (confirm(`Fix applied, but ${currentErrors.length} errors remain. Continue fixing?`)) {
1659 |                         // Recursively fix the *new* first error (since layout changed)
1660 |                         return await fixNext(0);
1661 |                     } else {
1662 |                         return false;
1663 |                     }
1664 |                 }
1665 | 
1666 |             } catch (e) {
1667 |                 if (confirm(`Auto-Fix Failed: ${e.message}\n\nTry again?`)) {
1668 |                     return await fixNext(index);
1669 |                 } else {
1670 |                     return false;
1671 |                 }
1672 |             }
1673 |         }
1674 | 
1675 |         return await fixNext(0);
1676 |     }
