3993 |     function formatBytes(bytes) {
3994 |         if (!bytes) return '0 B';
3995 |         const k = 1024;
3996 |         const sizes = ['B', 'KB', 'MB', 'GB'];
3997 |         const i = Math.floor(Math.log(bytes) / Math.log(k));
3998 |         return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
3999 |     }
