4001 |     function timeAgo(dateString) {
4002 |         const date = new Date(dateString);
4003 |         const now = new Date();
4004 |         const seconds = Math.floor((now - date) / 1000);
4005 |         if (seconds < 10) return 'just now';
4006 |         if (seconds < 60) return seconds + 's ago';
4007 |         const minutes = Math.floor(seconds / 60);
4008 |         if (minutes < 60) return minutes + 'm ago';
4009 |         const hours = Math.floor(minutes / 60);
4010 |         if (hours < 24) return hours + 'h ago';
4011 |         return date.toLocaleDateString();
4012 |     }
